import numpy as np

# {Priority Adaptive Routing System (PARS), dynamically ranks node sequence by incorporating urgency metrics and efficiency factors.}

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    best_priority = -float('inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        distance = calculate_distance(cur_truck_pos, customer_pos)
        travel_time = distance / truck_speed
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[i]

        if arrival_time > end_window:
            priority = -float('inf')
        else:
            urgency_priority = 1 / (1 + max(end_window - arrival_time, 0))
            efficiency_priority = 1 / (1 + distance)
            truck_distribution_priority = sum(1 for other_truck_pos in all_truck_pos if calculate_distance(customer_pos, other_truck_pos) < distance)

            priority = urgency_priority * 2 + efficiency_priority - truck_distribution_priority

        if priority > best_priority:
            best_priority = priority
            best_node = i

    return best_node
